import heapq

def top_k(lst, k):
    # Handle edge cases
    if k <= 0:
        return []
    if k >= len(lst):
        return sorted(lst, reverse=True)

    heap = []
    for val in lst:
        heapq.heappush(heap, val)
        if len(heap) > k:
            heapq.heappop(heap)
    return sorted(heap, reverse=True)
```

