import asyncio
import aiohttp
from typing import List, Dict

class AsyncUserDataFetcher:
    def __init__(self, base_url: str = "https://api.example.com", 
                 timeout: int = 10,
                 max_retries: int = 3):
        self.base_url = base_url
        self.timeout = aiohttp.ClientTimeout(total=timeout)
        self.max_retries = max_retries

    async def get_user_data(self, user_ids: List[str]) -> List[Dict]:
        """Fetch user data asynchronously."""
        async with aiohttp.ClientSession(timeout=self.timeout) as session:
            tasks = [self._fetch_single_user(session, uid) for uid in user_ids]
            results = await asyncio.gather(*tasks, return_exceptions=True)

            return [
                result if isinstance(result, dict) 
                else self._error_response(user_ids[i], "exception")
                for i, result in enumerate(results)
            ]

    async def _fetch_single_user(self, session: aiohttp.ClientSession, 
                                 user_id: str) -> Dict:
        """Fetch single user with async/await."""
        url = f"{self.base_url}/users/{user_id}"

        for attempt in range(self.max_retries):
            try:
                async with session.get(url) as response:
                    response.raise_for_status()
                    data = await response.json()

                    return {
                        "id": user_id,
                        "name": data.get("name"),
                        "email": data.get("email"),
                        "status": "success"
                    }

            except aiohttp.ClientResponseError as e:
                if e.status == 404:
                    return self._error_response(user_id, "not_found")
                elif e.status >= 500 and attempt < self.max_retries - 1:
                    await asyncio.sleep(2 ** attempt)
                    continue
                else:
                    return self._error_response(user_id, "http_error")

            except asyncio.TimeoutError:
                if attempt < self.max_retries - 1:
                    continue
                return self._error_response(user_id, "timeout")

            except Exception as e:
                logger.error(f"Unexpected error for user {user_id}: {e}")
                return self._error_response(user_id, "unknown_error")

        return self._error_response(user_id, "max_retries_exceeded")

    def _error_response(self, user_id: str, error_type: str) -> Dict:
        """Generate standardized error response."""
        return {
            "id": user_id,
            "name": None,
            "email": None,
            "status": "error",
            "error_type": error_type
        }
