from collections import OrderedDict
from datetime import datetime, timedelta
from typing import Any, Optional, Callable
import threading

class Cache:
    """A flexible cache implementation with multiple eviction policies."""

    def __init__(self, max_size: int = 100, ttl: Optional[int] = None, 
                 eviction_policy: str = 'lru'):
        """
        Initialize cache.

        Args:
            max_size: Maximum number of items in cache
            ttl: Time-to-live in seconds (None for no expiration)
            eviction_policy: 'lru' (least recently used), 'lfu' (least frequently used), 
                           or 'fifo' (first in, first out)
        """
        self.max_size = max_size
        self.ttl = ttl
        self.eviction_policy = eviction_policy

        self._cache = OrderedDict()
        self._timestamps = {}
        self._frequencies = {}
        self._lock = threading.RLock()

    def get(self, key: str, default: Any = None) -> Any:
        """Get value from cache."""
        with self._lock:
            # Check if key exists and hasn't expired
            if key in self._cache:
                if self._is_expired(key):
                    self._evict(key)
                    return default

                # Update access patterns based on policy
                if self.eviction_policy == 'lru':
                    self._cache.move_to_end(key)
                elif self.eviction_policy == 'lfu':
                    self._frequencies[key] = self._frequencies.get(key, 0) + 1

                return self._cache[key]

            return default

    def set(self, key: str, value: Any) -> None:
        """Set value in cache."""
        with self._lock:
            # Remove key if it already exists (to update position)
            if key in self._cache:
                self._evict(key)

            # Check if we need to make room
            if len(self._cache) >= self.max_size:
                self._evict_by_policy()

            # Add the new item
            self._cache[key] = value
            self._timestamps[key] = datetime.now()

            if self.eviction_policy == 'lfu':
                self._frequencies[key] = 1

    def delete(self, key: str) -> bool:
        """Delete key from cache."""
        with self._lock:
            if key in self._cache:
                self._evict(key)
                return True
            return False

    def clear(self) -> None:
        """Clear all items from cache."""
        with self._lock:
            self._cache.clear()
            self._timestamps.clear()
            self._frequencies.clear()

    def size(self) -> int:
        """Get current cache size."""
        return len(self._cache)

    def _is_expired(self, key: str) -> bool:
        """Check if key has expired."""
        if self.ttl is None:
            return False

        timestamp = self._timestamps.get(key)
        if timestamp is None:
            return True

        return datetime.now() - timestamp > timedelta(seconds=self.ttl)

    def _evict(self, key: str) -> None:
        """Remove key from cache and all tracking structures."""
        self._cache.pop(key, None)
        self._timestamps.pop(key, None)
        self._frequencies.pop(key, None)

    def _evict_by_policy(self) -> None:
        """Evict item based on configured policy."""
        if not self._cache:
            return

        if self.eviction_policy == 'lru':
            # Remove least recently used (first item in OrderedDict)
            key = next(iter(self._cache))
            self._evict(key)

        elif self.eviction_policy == 'lfu':
            # Remove least frequently used
            if self._frequencies:
                key = min(self._frequencies, key=self._frequencies.get)
                self._evict(key)

        elif self.eviction_policy == 'fifo':
            # Remove first item added
            key = next(iter(self._cache))
            self._evict(key)


class CacheDecorator:
    """Decorator for caching function results."""

    def __init__(self, cache: Optional[Cache] = None, key_func: Optional[Callable] = None):
        """
        Initialize cache decorator.

        Args:
            cache: Cache instance to use (creates new one if None)
            key_func: Function to generate cache key from arguments
        """
        self.cache = cache or Cache()
        self.key_func = key_func or self._default_key_func

    def _default_key_func(self, *args, **kwargs):
        """Generate cache key from function arguments."""
        return str(args) + str(sorted(kwargs.items()))

    def __call__(self, func):
        """Decorator implementation."""
        def wrapper(*args, **kwargs):
            # Generate cache key
            cache_key = f"{func.__name__}:{self.key_func(*args, **kwargs)}"

            # Try to get from cache
            result = self.cache.get(cache_key)
            if result is not None:
                return result

            # Compute and cache result
            result = func(*args, **kwargs)
            self.cache.set(cache_key, result)
            return result

        wrapper.cache = self.cache
        wrapper.clear_cache = self.cache.clear
        return wrapper


