    cache = Cache(max_size=3, ttl=60, eviction_policy='lru')

    # Set some values
    cache.set("user:1", {"name": "Alice", "age": 30})
    cache.set("user:2", {"name": "Bob", "age": 25})
    cache.set("user:3", {"name": "Charlie", "age": 35})

