import redis
import pickle
import json
from typing import Any, Optional, Union
from datetime import timedelta

class RedisCache:
    """Redis-based distributed cache implementation."""

    def __init__(self, host: str = 'localhost', port: int = 6379, 
                 db: int = 0, password: Optional[str] = None,
                 serializer: str = 'pickle'):
        """
        Initialize Redis cache.

        Args:
            host: Redis host
            port: Redis port
            db: Redis database number
            password: Redis password
            serializer: 'pickle' or 'json'
        """
        self.redis_client = redis.Redis(
            host=host, 
            port=port, 
            db=db, 
            password=password,
            decode_responses=False
        )
        self.serializer = serializer

    def _serialize(self, value: Any) -> bytes:
        """Serialize value for storage."""
        if self.serializer == 'pickle':
            return pickle.dumps(value)
        elif self.serializer == 'json':
            return json.dumps(value).encode('utf-8')
        else:
            raise ValueError(f"Unknown serializer: {self.serializer}")

    def _deserialize(self, data: bytes) -> Any:
        """Deserialize value from storage."""
        if data is None:
            return None

        if self.serializer == 'pickle':
            return pickle.loads(data)
        elif self.serializer == 'json':
            return json.loads(data.decode('utf-8'))
        else:
            raise ValueError(f"Unknown serializer: {self.serializer}")

    def get(self, key: str, default: Any = None) -> Any:
        """Get value from cache."""
        try:
            data = self.redis_client.get(key)
            if data is None:
                return default
            return self._deserialize(data)
        except Exception as e:
            print(f"Cache get error: {e}")
            return default

    def set(self, key: str, value: Any, ttl: Optional[int] = None) -> bool:
        """
        Set value in cache.

        Args:
            key: Cache key
            value: Value to cache
            ttl: Time-to-live in seconds
        """
        try:
            serialized = self._serialize(value)
            if ttl:
                return self.redis_client.setex(key, ttl, serialized)
            else:
                return self.redis_client.set(key, serialized)
        except Exception as e:
            print(f"Cache set error: {e}")
            return False

    def delete(self, key: str) -> bool:
        """Delete key from cache."""
        return bool(self.redis_client.delete(key))

    def exists(self, key: str) -> bool:
        """Check if key exists."""
        return bool(self.redis_client.exists(key))

    def clear(self) -> None:
        """Clear all keys in current database."""
        self.redis_client.flushdb()

    def get_many(self, keys: list) -> dict:
        """Get multiple values at once."""
        if not keys:
            return {}

        values = self.redis_client.mget(keys)
        return {
            key: self._deserialize(value) 
            for key, value in zip(keys, values) 
            if value is not None
        }

    def set_many(self, mapping: dict, ttl: Optional[int] = None) -> bool:
        """Set multiple values at once."""
        if not mapping:
            return True

        # Serialize all values
        serialized = {k: self._serialize(v) for k, v in mapping.items()}

        if ttl:
            # Use pipeline for atomic operation with TTL
            pipe = self.redis_client.pipeline()
            for key, value in serialized.items():
                pipe.setex(key, ttl, value)
            pipe.execute()
            return True
        else:
            return self.redis_client.mset(serialized)

    def increment(self, key: str, amount: int = 1) -> int:
        """Increment numeric value."""
        return self.redis_client.incr(key, amount)

    def decrement(self, key: str, amount: int = 1) -> int:
        """Decrement numeric value."""
        return self.redis_client.decr(key, amount)


